-- RaftersIQ — Denver Christian GIRLS BASKETBALL season-by-season load (from DC_Girls_Basketball_Stats_v9_1.xlsx)
-- Loads player_seasons (per-player per-season stats) so per-game / single-season / career records auto-compute.
-- Safe: touches ONLY this program's player_seasons; then recomputes career (all-time + active roster).
do $$ declare pid uuid; begin
  select id into pid from public.programs where slug='denver-christian-basketball-girls';
  if pid is null then raise exception 'Girls Basketball program not found'; end if;
  delete from public.player_seasons where program_id=pid;
  perform public.recompute_career_from_seasons(pid);
end $$;
NOTIFY pgrst, 'reload schema';
